const categories = [
	"All",
	"Insecticides",
	"Herbicides",
	"Fungicides",
	"Seeds",
  "plant",
];

const ProductsPage = () => {
	const [activeCategory, setActiveCategory] = useState("All");
	const [searchQuery, setSearchQuery] = useState("");

	// --- Filter Logic ---
	const filteredProducts = allProducts.filter((product) => {
		const matchesCategory =
			activeCategory === "All" || product.category === activeCategory;
		const matchesSearch = product.name
			.toLowerCase()
			.includes(searchQuery.toLowerCase());
		return matchesCategory && matchesSearch;
	});

	return (
		<div className="bg-gray-50 min-h-screen font-sans">
			{/* 1. Header Banner */}
			<div className="bg-[#1a4d2e] py-12 md:py-20 text-center text-white relative overflow-hidden">
				{/* Decorative Circles */}
				<div className="absolute top-0 left-0 w-32 h-32 bg-white opacity-5 rounded-full -translate-x-10 -translate-y-10"></div>
				<div className="absolute bottom-0 right-0 w-48 h-48 bg-yellow-500 opacity-10 rounded-full translate-x-10 translate-y-10"></div>

				<h1 className="text-4xl md:text-5xl font-bold mb-4 relative z-10">
					Our Products
				</h1>
				<p className="text-green-100 max-w-xl mx-auto text-lg relative z-10">
					Explore our range of high-quality agricultural solutions designed to
					maximize your yield.
				</p>
			</div>

			<div className="container mx-auto px-4 py-12 flex flex-col md:flex-row gap-8">
				{/* 2. Sidebar Filters (Desktop) / Top Bar (Mobile) */}
				<div className="w-full md:w-1/4 flex-shrink-0">
					<div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 sticky top-24">
						{/* Search Box */}
						<div className="relative mb-8">
							<input
  type="text"
  placeholder="Search products..."
  value={searchQuery}
  onChange={(e) => setSearchQuery(e.target.value)}
  className="w-full pl-10 pr-4 py-3 rounded-lg transition-all border border-gray-200 bg-white text-gray-800 placeholder-gray-400 focus:ring-2 focus:ring-green-500 focus:outline-none dark:bg-gray-900 dark:border-gray-700 dark:text-gray-100 dark:placeholder-gray-500 dark:focus:ring-green-400"
/>

							<Search className="absolute left-3 top-3.5 text-gray-400" size={18} />
						</div>

						{/* Category List */}
						<h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
							<Filter size={18} /> Categories
						</h3>
						<div className="flex flex-row md:flex-col gap-2 overflow-x-auto pb-4 md:pb-0 scrollbar-hide">
							{categories.map((cat) => (
								<button
									key={cat}
									onClick={() => setActiveCategory(cat)}
									className={`text-left px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap
                    ${
											activeCategory === cat
												? "bg-green-100 text-green-800 border-l-4 border-green-600"
												: "text-gray-600 hover:bg-gray-50 hover:text-green-700"
										}`}
								>
									{cat}
								</button>
							))}
						</div>
					</div>
				</div>

				{/* 3. Product Grid Area */}
				<div className="w-full md:w-3/4">
					{/* Results Count */}
					<div className="mb-6 text-gray-500 text-sm">
						Showing {filteredProducts.length} results for{" "}
						<span className="font-bold text-gray-800">&quot;{activeCategory}&quot;</span>
					</div>

					{/* Grid */}
					{filteredProducts.length > 0 ? (
						<div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
							{filteredProducts.map((product) => (
								<Link
									href={`/products/${product.id}`}
									key={product.id}
									className="block group"
								>
									<div
										key={product.id}
										className="bg-white rounded-xl overflow-hidden shadow-sm hover:shadow-xl transition-shadow duration-300 border border-gray-100 group flex flex-col"
									>
										{/* Product Image */}
										<div className="relative h-56 bg-gray-100 overflow-hidden">
											<Image
												src={product.image}
												alt={product.name}
												fill
												className="object-cover group-hover:scale-110 transition-transform duration-500"
											/>
											{/* Category Tag */}
											<span className="absolute top-3 left-3 bg-yellow-400 text-black text-xs font-bold px-2 py-1 rounded shadow-sm">
												{product.category}
											</span>
										</div>

										{/* Product Info */}
										<div className="p-5 flex flex-col flex-grow">
											<h3 className="text-lg font-bold text-gray-800 mb-2 group-hover:text-green-700 transition-colors">
												{product.name}
											</h3>
											<p className="text-gray-500 text-sm mb-4 line-clamp-2 flex-grow">
												{product.description}
											</p>

											{/* Rating Placeholder */}
											<div className="flex items-center gap-1 mb-4">
												{[1, 2, 3, 4, 5].map((star) => (
													<Star
														key={star}
														size={14}
														className="text-yellow-400 fill-yellow-400"
													/>
												))}
												<span className="text-xs text-gray-400 ml-1">
													(45 reviews)
												</span>
											</div>

											{/* <div className="border-t border-gray-100 pt-4 flex items-center justify-between mt-auto">
                      <div>
                        <span className="text-xs text-gray-400 block">Price</span>
                        <span className="text-xl font-bold text-green-800">₹{product.price}</span>
                      </div>
                      <button className="bg-green-700 hover:bg-green-800 text-white p-3 rounded-lg transition-colors shadow-md">
                        <ShoppingCart size={20} />
                      </button>
                    </div> */}
										</div>
									</div>
								</Link>
							))}
						</div>
					) : (
						/* Empty State */
						<div className="bg-white p-12 text-center rounded-xl border border-dashed border-gray-300">
							<div className="mx-auto w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mb-4">
								<Search className="text-gray-400" size={32} />
							</div>
							<h3 className="text-lg font-bold text-gray-800">
								No products found
							</h3>
							<p className="text-gray-500">
								Try adjusting your search or category filter.
							</p>
							<button
								onClick={() => {
									setActiveCategory("All");
									setSearchQuery("");
								}}
								className="mt-4 text-green-700 font-semibold hover:underline"
							>
								Clear all filters
							</button>
						</div>
					)}
				</div>
			</div>
		</div>
	);
};

export default ProductsPage;